#!/usr/bin/env node
/**
 * Session 4: 100 MC-Fragen (Recht).
 */
import fs from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const OUT = path.join(__dirname, 'fragen-updates.jsonl')
const STATE = path.join(__dirname, 'state.json')

const updates = [
  { id: '2f321eae-4edb-4aaf-bd40-6b7ad1b71c48', fachbereich: 'Recht', musterlosung: 'Die Brevi manu traditio («Übergabe kurzer Hand») ist eine der vereinfachten Übergabeformen beim Eigentumserwerb. Die Sache befindet sich bereits im Besitz des Erwerbers (z.B. geliehen, gemietet). Eine physische Übergabe ist nicht nötig — die blosse Willenserklärung der Eigentumsübertragung genügt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Sache bereits beim Erwerber, Übertragung durch Willenserklärung allein.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre ein gewöhnlicher Erwerb durch Versteigerung — nicht die Brevi manu traditio.' }, { feld: 'optionen', id: 'opt-2', text: 'Das wäre das Besitzkonstitut — Sache bleibt beim Veräusserer.' }, { feld: 'optionen', id: 'opt-3', text: 'Das wäre eine Besitzanweisung an einen Dritten — nicht dasselbe.' } ] },
  { id: '2f52174d-d7e0-4f22-a992-3815e2586d36', fachbereich: 'Recht', musterlosung: 'Nach OR 336c ist eine Kündigung während der Schwangerschaft absolut nichtig — unabhängig davon, ob der Arbeitgeber davon wusste. Die Sperrfrist ist formal und wirkt objektiv. Ein Rückzugsversuch ändert nichts an der Nichtigkeit. Die Arbeitnehmerin kann Wiedereinstellung verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Schwangerschaft = absolute Sperrfrist nach OR 336c.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein Wahlrecht — die Kündigung ist nichtig, nicht nur missbräuchlich.' }, { feld: 'optionen', id: 'opt-2', text: 'Kenntnis des AG ist unerheblich — OR 336c wirkt objektiv.' }, { feld: 'optionen', id: 'opt-3', text: 'Schriftform heilt die Sperrfristverletzung nicht.' } ] },
  { id: '2f5b397f-832f-4815-b2fc-56493e9e368f', fachbereich: 'Recht', musterlosung: 'Die Schlichtung (Art. 197 ZPO) ist in der Schweiz vor einer Zivilklage grundsätzlich obligatorisch. Die Schlichtungsbehörde kann bei kleinen Streitwerten sogar entscheiden oder Urteilsvorschläge machen. Die Mediation (Art. 213 ff. ZPO) ist dagegen freiwillig; der Mediator hat keine Entscheidungsgewalt, sondern unterstützt die Parteien bei einer eigenen Lösung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Mediator entscheidet gerade nicht verbindlich — das ist sein Wesensmerkmal.' }, { feld: 'optionen', id: 'opt-1', text: 'Umgekehrt: Schlichtung ist obligatorisch, Mediation freiwillig.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Mediation freiwillig ohne Entscheidung, Schlichtung obligatorisch mit Urteilsvorschlag.' }, { feld: 'optionen', id: 'opt-3', text: 'Verschiedene Verfahren mit unterschiedlichem Charakter — nicht dasselbe.' } ] },
  { id: '3002e35c-8391-4751-a2da-b2f4abbb7f93', fachbereich: 'Recht', musterlosung: 'Schiedsverfahren bieten Vertraulichkeit, Schnelligkeit und spezialisierte Schiedsrichter — ein echter Mehrwert bei komplexen Fällen. Nachteilig sind hingegen die Kosten (Parteien zahlen die Schiedsrichter selbst) und die stark eingeschränkten Anfechtungsmöglichkeiten eines Schiedsspruchs. Die Parteien müssen diese Abwägung treffen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Schiedsspruch ist gerade verbindlich — das ist ein Wesensmerkmal.' }, { feld: 'optionen', id: 'opt-1', text: 'Anwälte sind zugelassen — Parteien können sich frei vertreten lassen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Hohe Kosten + eingeschränkte Anfechtung sind die zentralen Nachteile.' }, { feld: 'optionen', id: 'opt-3', text: 'Schiedsverfahren sind oft kürzer, nicht länger — Schnelligkeit ist ein Vorteil.' } ] },
  { id: '328f413f-e2b7-4d09-8537-beb6a4ae0916', fachbereich: 'Recht', musterlosung: 'Juristische Personen handeln durch ihre Organe (z.B. Verwaltungsrat). Nach Art. 54 ZGB werden sie handlungsfähig, sobald die nach Gesetz und Statuten notwendigen Organe bestellt sind. Fehlen diese Organe, ist die juristische Person handlungsunfähig — sie kann keine rechtsverbindlichen Handlungen vornehmen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'HR-Eintrag begründet die Rechtsfähigkeit, nicht direkt die Handlungsfähigkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Bestellung der Organe macht die juristische Person handlungsfähig (Art. 54 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Ohne Organe kann keine Willenserklärung erfolgen — Vertragsabschluss wäre nicht möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Gründung reicht nicht — ohne Organe bleibt die juristische Person handlungsunfähig.' } ] },
  { id: '32a175f2-08cc-41fe-b2a0-c42df8849d3a', fachbereich: 'Recht', musterlosung: 'Die objektive Tatbestandsmässigkeit ist die erste Prüfungsstufe im strafrechtlichen Falllösungsschema. Sie prüft, ob der äussere Sachverhalt die Tatbestandsmerkmale einer Norm im besonderen Teil des StGB (Art. 111 ff.) erfüllt. Die innere Einstellung des Täters (Vorsatz/Fahrlässigkeit) wird erst auf der subjektiven Stufe geprüft.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Schuldfähigkeit ist eine spätere Prüfungsstufe (Schuld), nicht Tatbestandsmässigkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Objektiv = äusserer Sachverhalt erfüllt TBM im besonderen Teil des StGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Rechtfertigungsgründe kommen erst nach Bejahung der Tatbestandsmässigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Vorsatz/Fahrlässigkeit ist die subjektive Tatbestandsmässigkeit — andere Stufe.' } ] },
  { id: '3329879b-73a3-4e17-9ad1-a7a76679f882', fachbereich: 'Recht', musterlosung: 'Nach Art. 17 und 18 ZGB ist handlungsunfähig, wer urteilsunfähig ist. Handlungsunfähige Personen können durch ihre Handlungen keine rechtliche Wirkung erzeugen. Ein Vertrag, den eine urteilsunfähige Person abschliesst, ist von Anfang an nichtig — er muss nicht angefochten werden und entfaltet nie Wirkung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Gutgläubigkeit der Gegenseite heilt die Nichtigkeit nicht (Art. 18 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Kein Beweis nötig — die Nichtigkeit folgt direkt aus der Urteilsunfähigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Vertrag nichtig nach Art. 18 ZGB — von Anfang an ungültig.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht nur anfechtbar — der Vertrag ist nichtig (stärker als Anfechtbarkeit).' } ] },
  { id: '3386582b-bc38-4529-897f-3d98c53744ce', fachbereich: 'Recht', musterlosung: 'Nach OR 327 stellt der Arbeitgeber dem Arbeitnehmer die zur Arbeitsausführung notwendigen Werkzeuge, Geräte und Materialien zur Verfügung. Alternativ kann der Arbeitnehmer eigenes Material verwenden, erhält dann aber eine angemessene Entschädigung. Es ist eine zwingende Schutznorm des Arbeitsrechts.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Forderung nötig — die Pflicht besteht ex lege nach OR 327.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: OR 327 verpflichtet den Arbeitgeber zur Bereitstellung der Arbeitsmittel.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — der Arbeitgeber trägt diese Kosten grundsätzlich.' }, { feld: 'optionen', id: 'opt-3', text: 'Die Pflicht gilt branchenübergreifend, nicht nur für Büroarbeit.' } ] },
  { id: '34e52237-08d0-4b55-ba9e-1070c7cb8a15', fachbereich: 'Recht', musterlosung: 'Bei einem schweren Mangel wie einem Heizungsausfall stehen Lina nach fruchtloser Nachfristsetzung mehrere Rechte zu: Ersatzvornahme auf Kosten des Vermieters (Art. 259b OR), Mietzinsreduktion für die Dauer der Beeinträchtigung (Art. 259d OR) und Schadenersatz für Folgeschäden (Art. 259e OR). Eine Hinterlegung wäre nur auf ein amtliches Konto zulässig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Sofortiger Auszug ohne Kündigung wäre Vertragsbruch — nicht zulässig.' }, { feld: 'optionen', id: 'opt-1', text: 'Abwarten schützt die Rechte nicht — Ansprüche müssen aktiv geltend gemacht werden.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Ersatzvornahme + Mietzinsreduktion + Schadenersatz (Art. 259b/d/e OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Hinterlegung nur auf amtliches Konto zulässig — Privatkonto ist keine gültige Hinterlegung.' } ] },
  { id: '34f5014c-56f6-45e9-a7f7-b85cd28b107f', fachbereich: 'Recht', musterlosung: 'Der Sohn wird durch Erbfolge Rechtsnachfolger des Vaters. Damit fallen Gläubiger- und Schuldnerstellung der Darlehensforderung in einer Person zusammen. Nach OR 118 erlischt die Obligation durch Vereinigung — man kann sich selbst nichts schulden. Die CHF 50\'000 sind damit keine durchsetzbare Forderung mehr.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Forderung ist erloschen — Einforderung gegen sich selbst unmöglich.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Erbfolge ändert sehr wohl etwas — Vereinigung lässt die Forderung erlöschen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Vereinigung nach OR 118 — Gläubiger und Schuldner in einer Person.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine automatische Verjährung — die Forderung erlischt durch Vereinigung, nicht Zeitablauf.' } ] },
  { id: '35205e45-ea8a-4d80-b97f-5c0e1bdda514', fachbereich: 'Recht', musterlosung: 'Oliver wusste vom Unfall und hat Petra trotzdem erklärt, das Auto sei unfallfrei. Damit liegt eine absichtliche Täuschung nach OR 28 vor — aktives Täuschungsverhalten über eine wesentliche Tatsache. Absichtliche Täuschung verdrängt den Grundlagenirrtum, der andernfalls ebenfalls vorläge. Petra kann den Vertrag anfechten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Absichtliche Täuschung nach OR 28 — wissentlich falsche Angabe.' }, { feld: 'optionen', id: 'opt-1', text: 'Grundlagenirrtum wird durch die absichtliche Täuschung verdrängt.' }, { feld: 'optionen', id: 'opt-2', text: 'Übervorteilung (OR 21) setzt Missverhältnis + Ausnutzung einer Schwäche voraus — nicht belegt.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein Erklärungsirrtum — Oliver wusste genau, was er sagte.' } ] },
  { id: '362662e9-e87d-41c7-b498-6b3d85aad3a9', fachbereich: 'Recht', musterlosung: 'Faustregel: Ein Glas (3 dl Bier) bewirkt bei einem 70-kg-Mann ca. 0,25 Promille. 4 Gläser ergeben somit ca. 1,0 Promille. Dies überschreitet den Grenzwert von 0,5 Promille (Fahrunfähigkeit) und auch den von 0,8 Promille (qualifizierte Trunkenheit). Rechtsfolge: Vergehen mit Strafregister-Eintrag.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '0,5 Promille wären nur 2 Gläser — bei 4 Gläsern klar zu wenig.' }, { feld: 'optionen', id: 'opt-1', text: '2,0 Promille wären 8 Gläser — Faustregel wird überschätzt.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Ca. 1,0 Promille — qualifizierte Trunkenheit, Strafregistereintrag.' }, { feld: 'optionen', id: 'opt-3', text: '0,25 Promille wären nur 1 Glas — Faustregel falsch angewendet.' } ] },
  { id: '36da4fda-cece-4ac3-8e1d-c1401b50c23c', fachbereich: 'Recht', musterlosung: 'Ein selbständiger Besitzer übt die Sachherrschaft mit Eigentümerwillen aus — typisch der Eigentümer selbst. Ein unselbständiger Besitzer hat die Sache aufgrund eines obligatorischen oder dinglichen Rechts vom Eigentümer erhalten (Mieter, Pächter, Pfandgläubiger, Nutzniesser). Beide sind Besitzer nach Art. 919 ZGB, unterscheiden sich aber in der Rechtsstellung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Selbständig = eigenes Herrschaftsrecht, unselbständig = abgeleitetes Recht.' }, { feld: 'optionen', id: 'opt-1', text: 'Zeitdauer ist kein Unterscheidungskriterium — Rechtsstellung zählt.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Begriffe sind nicht synonym — sie bezeichnen unterschiedliche Rechtsstellungen.' }, { feld: 'optionen', id: 'opt-3', text: 'Diebstahl begründet unrechtmässigen Besitz — der Unterschied betrifft Rechtsgrundlage.' } ] },
  { id: '379d0fe0-8998-4349-9c08-fe61882abd44', fachbereich: 'Recht', musterlosung: 'Der Bruttolohn besteht aus dem vereinbarten Grundlohn plus allfälligen Zuschlägen (Überstunden, Nacht-/Sonntagsarbeit), dem 13. Monatslohn sowie Gratifikationen. Nach Abzug von Sozialversicherungen, Steuern und weiteren Abzügen ergibt sich der Nettolohn, der auf das Konto überwiesen wird.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Grundlohn + Zuschläge + 13. Monatslohn + Gratifikation = Bruttolohn.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre der Nettolohn — nach allen Abzügen.' }, { feld: 'optionen', id: 'opt-2', text: 'Unvollständig — Zuschläge und Zusatzkomponenten fehlen.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsche Richtung — Bruttolohn ist vor Steuern, nicht Nettolohn minus Steuern.' } ] },
  { id: '37a291af-d2f0-49d9-b29d-e673919f5d33', fachbereich: 'Recht', musterlosung: 'Grundrechte können nach Art. 36 BV unter drei kumulativen Voraussetzungen eingeschränkt werden: gesetzliche Grundlage, öffentliches Interesse (z.B. Gesundheitsschutz) und Verhältnismässigkeit. Auch Notverordnungen des Bundesrates brauchen eine Grundlage (z.B. Epidemiengesetz). Der Kerngehalt des Grundrechts muss stets gewahrt bleiben.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur das Parlament — auch der Bundesrat kann im Rahmen delegierter Kompetenz.' }, { feld: 'optionen', id: 'opt-1', text: 'Auch Notverordnungen benötigen eine gesetzliche Grundlage.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Art. 36 BV — gesetzl. Grundlage + öffentl. Interesse + Verhältnismässigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Einschränkungen sind unter Bedingungen möglich — nicht absolut verboten.' } ] },
  { id: '381bb03a-6b66-4d96-b08e-7f62a1f7ceb3', fachbereich: 'Recht', musterlosung: 'Das StGB kennt vier Vollzugsformen: Normalvollzug (Art. 77), Arbeitsexternat (Art. 77a), Halbgefangenschaft (Art. 77b) und elektronische Überwachung (Art. 79 Abs. 1). Die Wahl richtet sich nach Strafhöhe, Sozialprognose und persönlichen Verhältnissen des Verurteilten. Ein blosser «Hausarrest ohne Kontrolle» ist nicht vorgesehen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Normalvollzug als Grundform (Art. 77 StGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Halbgefangenschaft nach Art. 77b StGB — tagsüber arbeiten, nachts Haft.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Elektronische Überwachung nach Art. 79 Abs. 1 StGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Hausarrest ohne Kontrolle kennt das StGB nicht — nur mit elektronischer Überwachung.' } ] },
  { id: '38ad65dd-a70f-4cbd-86a8-7fdd660a915a', fachbereich: 'Recht', musterlosung: 'Relative (obligatorische) Rechte gelten nur zwischen den Parteien eines Schuldverhältnisses — z.B. ein Kaufvertrag wirkt nur zwischen Käufer und Verkäufer. Absolute (dingliche) Rechte gewähren dagegen ein Herrschaftsrecht an einer Sache, das gegenüber jedermann durchgesetzt werden kann. Klassisch absolut: Eigentum, beschränkt dingliche Rechte.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Falsch — die Unterscheidung betrifft Wirkungskreis, nicht Sachtyp.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — die Zeit ist nicht das entscheidende Kriterium.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — die Entstehungsart unterscheidet nicht relative von absoluten Rechten.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Relativ wirkt nur inter partes, absolut gegen jedermann.' } ] },
  { id: '38b60dc7-91b0-491b-8436-a1b1cec0e5a8', fachbereich: 'Recht', musterlosung: 'Die Einwilligung ist ein Rechtfertigungsgrund: Willigt die betroffene Person in eine Handlung ein, die sonst strafbar wäre, entfällt die Widerrechtlichkeit. Bei einer Operation würde der Tatbestand der Körperverletzung erfüllt — die Zustimmung der Patientin macht den Eingriff jedoch rechtmässig. Notwehr und Notstand sind andere Rechtfertigungsgründe.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das ist eine gesetzlich erlaubte Handlung der Polizei — anderer Rechtfertigungsgrund.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre Notwehr (Art. 15 StGB) — Abwehr eines rechtswidrigen Angriffs.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Einwilligung der Patientin rechtfertigt die eigentlich tatbestandsmässige Körperverletzung.' }, { feld: 'optionen', id: 'opt-3', text: 'Das wäre Notstand (Art. 17 StGB) — Rettung eines höherwertigen Rechtsguts.' } ] },
  { id: '38e3518e-0da7-40a9-a732-a81e0beb35fd', fachbereich: 'Recht', musterlosung: 'Moral beruht auf subjektiven Werten, Sitte auf gesellschaftlicher Gewohnheit. Beide sind nicht erzwingbar und unterliegen Wandel. Für das Zusammenleben braucht es verbindliche, staatlich durchsetzbare Regeln — das Recht schafft Rechtssicherheit und Berechenbarkeit für alle Mitglieder der Gesellschaft.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Moral und Sitte sind keineswegs verdrängt — sie wirken weiter neben dem Recht.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Subjektivität und fehlende Durchsetzbarkeit machen Moral/Sitte allein ungenügend.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Staat hat Interesse an Recht — nicht an Moral direkt.' }, { feld: 'optionen', id: 'opt-3', text: 'Moral ist universal, nicht auf Religiöse beschränkt.' } ] },
  { id: '38f193f7-0317-4b15-b279-734b7dc874a3', fachbereich: 'Recht', musterlosung: 'Die heimliche Videoüberwachung greift ohne Einwilligung der Angestellten in deren Persönlichkeitsrecht ein. Art. 28 ZGB wertet jede Persönlichkeitsverletzung als widerrechtlich, sofern kein Rechtfertigungsgrund vorliegt. Ein pauschales Arbeitgeberinteresse genügt nicht — für verdeckte Überwachung fehlen gesetzliche Grundlage, Verhältnismässigkeit und Transparenz.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das Weisungsrecht rechtfertigt keine heimliche Überwachung — Grenzen aus Art. 328 OR.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Widerrechtliche Persönlichkeitsverletzung ohne Rechtfertigungsgrund.' }, { feld: 'optionen', id: 'opt-2', text: 'Auch am Arbeitsplatz besteht Schutz der Privatsphäre (Art. 328 OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Die Widerrechtlichkeit besteht ex lege — kein Protest nötig.' } ] },
  { id: '3a26c890-eee8-4c77-8846-c0c3b35d6e28', fachbereich: 'Recht', musterlosung: 'Das Bundesgericht ist die höchste Instanz und sorgt für einheitliche Rechtsanwendung in der ganzen Schweiz. Die Sachverhaltsfeststellung und Beweiswürdigung erfolgt primär vor den kantonalen Instanzen. Das Bundesgericht greift nur ein, wenn Sachverhalt offensichtlich unrichtig festgestellt wurde — ansonsten beschränkt es sich auf Rechtsfragen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beweismittel sind erlaubt — der Punkt ist die primäre Rolle der Vorinstanzen.' }, { feld: 'optionen', id: 'opt-1', text: 'Das Bundesgericht ist für alle Rechtsgebiete zuständig, nicht nur Strafsachen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Sachverhalt liegt bei Vorinstanzen, BG sichert einheitliche Rechtsanwendung.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Sachverhalt kann in der zweiten Instanz noch ergänzt werden — nicht zementiert.' } ] },
  { id: '3a6cfbfa-7f90-49b6-8284-3bcb927e1603', fachbereich: 'Recht', musterlosung: 'Nach Art. 28 ZGB kann die verletzte Person zivilrechtlich mehrere Ansprüche geltend machen: Beseitigung, Unterlassung (Verbot einer drohenden Verletzung), Feststellung, Schadenersatz für Vermögensschäden und Genugtuung für immateriellen Schaden. Eine Freiheitsstrafe ist keine zivilrechtliche Folge von Art. 28 ZGB, sondern eine Sanktion des Strafrechts.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Schadenersatz für materiellen Schaden.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Genugtuung für immateriellen Schaden.' }, { feld: 'optionen', id: 'opt-2', text: 'Freiheitsstrafe ist strafrechtliche Sanktion — nicht Folge von Art. 28 ZGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Unterlassungs-/Verbotsklage gegen drohende Verletzung.' } ] },
  { id: '3a7638cf-4d82-443d-a784-9b861813f683', fachbereich: 'Recht', musterlosung: 'Eigentum ist das umfassendste dingliche Recht an einer Sache (Art. 641 ZGB) — es verleiht alleinige rechtliche Herrschaft. Besitz dagegen ist kein Recht, sondern die tatsächliche Gewalt über eine Sache (Art. 919 ZGB). Besitz und Eigentum können auseinanderfallen: Der Mieter ist Besitzer, aber nicht Eigentümer.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Zeit ist kein Unterscheidungskriterium — beide können zeitlich variieren.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Eigentum = Recht an Sache, Besitz = tatsächliche Gewalt.' }, { feld: 'optionen', id: 'opt-2', text: 'Nutzungsrecht steht dem Eigentümer zu — Besitzer kann je nach Rechtstitel mehr oder weniger.' }, { feld: 'optionen', id: 'opt-3', text: 'Beide Kategorien gelten für alle Sachen — Grundstücke und bewegliche Sachen.' } ] },
  { id: '3ac94a44-dc13-4a5b-ac98-740c34295169', fachbereich: 'Recht', musterlosung: 'Freiheitsstrafen verursachen hohe direkte Kosten (z.B. CHF 301.–/Tag im Normalvollzug) und negative Folgen für Täter und Umfeld (Resozialisierungshürden, Familienbelastung). Das StGB sieht alternative Vollzugsformen vor, um unnötiges Leid zu vermeiden und ganzheitlich günstigere Lösungen zu ermöglichen. Die niedrigsten direkten Kosten sind nicht immer die gesamtwirtschaftlich besten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Kosten/Nutzen-Abwägung — negative Effekte und hohe Kosten vermeiden.' }, { feld: 'optionen', id: 'opt-1', text: 'Die BV verbietet Freiheitsstrafen nicht — sie sind als ultima ratio zulässig.' }, { feld: 'optionen', id: 'opt-2', text: 'Es gibt auch längere Freiheitsstrafen in der Schweiz, inkl. lebenslänglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Platzmangel ist kein Leitmotiv — die Vielfalt dient Resozialisierung und Effizienz.' } ] },
  { id: '3b152909-5bd6-480b-a26a-33ccd12859ff', fachbereich: 'Recht', musterlosung: 'Das strafrechtliche Falllösungsschema folgt mehreren Prüfungsschritten: Tatbestandsmässigkeit (objektiv und subjektiv), Rechtswidrigkeit (Rechtfertigungsgründe), Schuld (Schuldausschliessungsgründe) sowie ggf. Strafantrag (Art. 30 StGB) und Verjährung (Art. 97 StGB). Die Zivilhaftung folgt eigenen Regeln und gehört nicht ins Strafrechts-Schema.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Erste Prüfungsstufe, objektiv und subjektiv.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Rechtfertigungsgründe wie Notwehr, Notstand, Einwilligung.' }, { feld: 'optionen', id: 'opt-2', text: 'Zivilhaftung ist keine Strafbarkeitsfrage — eigenes Gebiet (OR 41 ff.).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Schuldausschliessungsgründe wie Schuldunfähigkeit, Notwehrexzess.' } ] },
  { id: '3ca05004-da2c-48c7-b5f5-d3421f98e8e8', fachbereich: 'Recht', musterlosung: 'OR 336c schützt Arbeitnehmerinnen absolut während der Schwangerschaft und in den 16 Wochen nach der Niederkunft. Jede Kündigung während dieser Sperrfrist ist nichtig, unabhängig vom Kündigungsgrund. Der Arbeitnehmer hat Recht: Schwangerschaft ist eine klassische Sperrfristsituation, die jede Kündigung nichtig macht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Grund ist unerheblich — Sperrfrist gilt absolut.' }, { feld: 'optionen', id: 'opt-1', text: 'Schriftform heilt die Sperrfristverletzung nicht.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Absolute Sperrfrist nach OR 336c — jede Kündigung nichtig.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Zeitpunkt der Mitteilung ist egal — objektiver Schutz.' } ] },
  { id: '3d19fbe7-138e-42e2-a619-9af59a665bea', fachbereich: 'Recht', musterlosung: 'Gewohnheitsrecht beruht auf althergebrachten, lang geübten Bräuchen, die als allgemein verbindlich anerkannt werden. Beispiele sind Handelsusanzen oder Ortsbräuche (z.B. 30-Tage-Monat bei Banken). In der Schweiz hat das Gewohnheitsrecht heute noch geringe praktische Bedeutung, da die meisten Rechtsgebiete kodifiziert sind.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Alte, fest gewordene Bräuche mit verpflichtender Wirkung.' }, { feld: 'optionen', id: 'opt-1', text: 'Gerichtsentscheide sind Rechtsprechung — nicht Gewohnheitsrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Alter macht Gesetze nicht zum Gewohnheitsrecht.' }, { feld: 'optionen', id: 'opt-3', text: 'Bundesratsregeln sind Verordnungen — keine Gewohnheitsregeln.' } ] },
  { id: '3d47b066-4b03-4a8c-ba02-00567dbed418', fachbereich: 'Recht', musterlosung: 'Die Verrechnung nach OR 120 erlischt beide Forderungen in Höhe der kleineren. A hat CHF 8\'000 an B zu zahlen, B hat CHF 5\'000 an A. Nach Verrechnung erlöschen beide Forderungen in Höhe von CHF 5\'000. Es verbleibt eine Restforderung von CHF 3\'000, die A an B schuldet.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beide erlöschen nur in Höhe der kleineren Forderung — nicht vollständig.' }, { feld: 'optionen', id: 'opt-1', text: 'Auch die kleinere erlischt — nur in Höhe der Verrechnung.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Gleichartigkeit (Geld) ist erfüllt — Verrechnung ist möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Erlöschen je CHF 5\'000, Restschuld A an B CHF 3\'000.' } ] },
  { id: '3d66679b-f987-43ef-94f9-e1fee0ba844f', fachbereich: 'Recht', musterlosung: 'Reto droht Sabine mit einem erheblichen Übel (Rufschädigung) — das ist Furchterregung nach OR 29. Gleichzeitig besteht ein offensichtliches Missverhältnis zwischen CHF 50\'000 und dem tatsächlichen Wert von CHF 200\'000, wobei Reto Sabines Zwangslage ausnutzt — das ist Übervorteilung nach OR 21. Sabine kann den Vertrag auf beiden Gründen anfechten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Grundlagenirrtum (OR 24) setzt Irrtum über wesentliche Sachverhalte voraus — hier liegt Druck vor.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur Furchterregung — auch Übervorteilung wegen Missverhältnis.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Furchterregung (OR 29) + Übervorteilung (OR 21) stehen beide zur Verfügung.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht nur Übervorteilung — die Drohung begründet zusätzlich Furchterregung.' } ] },
  { id: '3e7fd48c-7941-4b2f-a6a5-619b3931d140', fachbereich: 'Recht', musterlosung: 'Das Prozessrecht (Verfahrensrecht) regelt, wie Rechte vor Gericht durchgesetzt werden — also den Ablauf von Gerichtsverfahren mit Fristen, Beweisregeln und Zuständigkeiten. Davon zu unterscheiden ist das materielle Recht, das die inhaltlichen Rechte und Pflichten regelt (z.B. OR, ZGB). Prozess- und materielles Recht ergänzen sich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Strafen sind Inhalt des materiellen Strafrechts — nicht des Prozessrechts.' }, { feld: 'optionen', id: 'opt-1', text: 'Verwaltungsorganisation ist Verwaltungsrecht — nicht Prozessrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Prozessrecht = Regeln zur Durchsetzung von Rechten vor Gericht.' }, { feld: 'optionen', id: 'opt-3', text: 'Inhaltliche Rechte/Pflichten sind materielles Recht — nicht prozessual.' } ] },
  { id: '3ee03f4e-cb60-40f6-b8da-92212d4f591a', fachbereich: 'Recht', musterlosung: 'Das staatliche Arbeitsrecht setzt Mindeststandards, die für alle gelten. Gesamtarbeitsverträge (GAV) und Normalarbeitsverträge (NAV) können weitergehende Schutzbestimmungen vorsehen — höhere Mindestlöhne, bessere Kündigungsfristen, zusätzliche Ferien. GAV sind besonders wichtig in Branchen mit Schutzbedarf und nicht überflüssig, auch wenn das Arbeitsrecht bereits viel regelt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'GAV haben rechtliche Wirkung — sie sind nicht rein symbolisch.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: GAV setzen höhere Standards und ergänzen das staatliche Arbeitsrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Schutz ist nie vollständig — GAV schliessen Lücken und heben Standards.' }, { feld: 'optionen', id: 'opt-3', text: 'GAV gelten branchenweit, unabhängig von der Betriebsgrösse.' } ] },
  { id: '3f2792c8-9848-4d92-a748-738c4a6cd832', fachbereich: 'Recht', musterlosung: 'Die Bürgschaft (OR 492) ist ein Sicherungsvertrag: Der Bürge verpflichtet sich gegenüber dem Gläubiger, für die Schuld des Hauptschuldners einzustehen, falls dieser nicht zahlt. Sie ist akzessorisch zur Hauptschuld. Formvorschrift: einfache Schriftform bei natürlichen Personen bis CHF 2\'000, darüber öffentliche Beurkundung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das wäre eine Kaution — anders strukturiert als die Bürgschaft.' }, { feld: 'optionen', id: 'opt-1', text: 'Versicherung ist ein eigener Vertragstyp — nicht Bürgschaft.' }, { feld: 'optionen', id: 'opt-2', text: 'Ein Eigentumsrecht wäre dingliche Sicherheit — hier personale Sicherheit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Bürge haftet akzessorisch für Schuld des Hauptschuldners (OR 492).' } ] },
  { id: '40795fc8-b6da-48a5-b432-8d28b43f5009', fachbereich: 'Recht', musterlosung: 'Bei gestohlenen oder anderweitig abhanden gekommenen Sachen gilt Art. 934 ZGB: Der Eigentümer kann sie während fünf Jahren von jedem Besitzer herausverlangen, auch vom gutgläubigen Erwerber. Die Regel zum Schutz des gutgläubigen Erwerbs (Art. 933 ZGB) greift nur bei anvertrauten Sachen, nicht bei abhanden gekommenen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Bei gestohlenen Sachen wird der gutgläubige Erwerber gerade nicht sofort Eigentümer.' }, { feld: 'optionen', id: 'opt-1', text: 'Der Dieb erlangt kein Eigentum durch Zeitablauf — nur Ersitzung unter strengen Voraussetzungen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Rückforderung während 5 Jahren nach Art. 934 ZGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Eigentümer behält seinen Anspruch — innert Frist durchsetzbar.' } ] },
  { id: '40f4442a-8734-4db3-a5b7-3acbc37d5b9d', fachbereich: 'Recht', musterlosung: 'Nach Art. 53 ZGB haben juristische Personen alle Rechte und Pflichten, die nicht die natürlichen Eigenschaften des Menschen voraussetzen. Rechte auf Leben, körperliche Unversehrtheit, Ehe oder elterliche Sorge stehen nur natürlichen Personen zu. Vertragsabschluss, Mitarbeitendenbeschäftigung und Eigentum sind dagegen ohne Weiteres möglich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Rechte, die das Menschsein voraussetzen (Leben, Ehe, körperliche Integrität).' }, { feld: 'optionen', id: 'opt-1', text: 'Verträge kann die juristische Person durch ihre Organe abschliessen.' }, { feld: 'optionen', id: 'opt-2', text: 'Als Arbeitgeberin ist die juristische Person handlungsfähig.' }, { feld: 'optionen', id: 'opt-3', text: 'Eigentum ist typisches Recht juristischer Personen (Vermögensrecht).' } ] },
  { id: '41fa1fc3-75ff-4581-bc8c-870f14e5ae28', fachbereich: 'Recht', musterlosung: 'Meinungsäusserungs- und Versammlungsfreiheit (Art. 16 und 22 BV) schützen grundsätzlich auch kontroverse Standpunkte — Grundrechte sind nicht auf Mehrheitsmeinungen beschränkt. Nach Art. 36 BV sind Einschränkungen möglich, wenn eine gesetzliche Grundlage, öffentliches Interesse (z.B. Schutz vor Rassendiskriminierung, Art. 261bis StGB) und Verhältnismässigkeit vorliegen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Grundrechte gelten für alle Menschen — auch für politisch Extreme.' }, { feld: 'optionen', id: 'opt-1', text: 'Auch Minderheitsmeinungen sind geschützt — das ist Kern der Meinungsfreiheit.' }, { feld: 'optionen', id: 'opt-2', text: 'Rassistische Aussagen sind nicht schrankenlos — Rassendiskriminierung ist strafbar (Art. 261bis StGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Grundsätzlich ja, aber einschränkbar nach Art. 36 BV zum Schutz Dritter.' } ] },
  { id: '43085c3e-2b7c-4c09-9dd0-aefa6f29bbe0', fachbereich: 'Recht', musterlosung: 'Bei der Wohnungsabgabe sollte der Mieter die Wohnung gründlich reinigen, Defekte dokumentieren (Fotos, Notizen) und mit dem Vermieter die Kostenaufteilung klären. Die Schlüssel werden erst bei offizieller Abnahme übergeben — nie unkontrolliert in den Briefkasten. So lassen sich spätere Streitigkeiten über Schäden und Kosten vermeiden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Gründliche Reinigung ist Mieterpflicht bei Wohnungsabgabe.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Dokumentation durch Fotos schafft Beweismittel.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gemeinsames Abnahmeprotokoll regelt die Kostenaufteilung.' }, { feld: 'optionen', id: 'opt-3', text: 'Schlüsselübergabe ohne Abnahme wäre nachteilig — keine gemeinsame Zustandsfeststellung.' } ] },
  { id: '4338ac5a-017f-407f-b6e9-b67b086f91fe', fachbereich: 'Recht', musterlosung: 'Hansli ist nach Art. 19 ZGB beschränkt handlungsunfähig. Jedes neue Rechtsgeschäft braucht die Zustimmung des gesetzlichen Vertreters. Die Zustimmung des Vaters bezog sich nur auf den Kauf eines Töfflis, nicht auf einen späteren Tausch. Ohne erneute Zustimmung wäre der Tausch schwebend unwirksam. Geringfügige Geschäfte oder unentgeltliche Vorteile sind Ausnahmen — ein Tausch fällt nicht darunter.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Weder Kauf noch Tausch ist automatisch erlaubt — jedes neue Geschäft braucht Zustimmung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Neue Zustimmung nötig nach Art. 19 Abs. 1 ZGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Ein Tausch ist nicht geringfügig — er erfordert Zustimmung.' }, { feld: 'optionen', id: 'opt-3', text: 'Beschränkte Handlungsunfähigkeit schränkt die Verfügungsfreiheit ein — auch bei eigenem Eigentum.' } ] },
  { id: '433d2699-d6a1-4fdd-9722-1425673823ef', fachbereich: 'Recht', musterlosung: 'Art. 47 StGB nennt drei zentrale Strafzumessungsfaktoren: das Ausmass der Rechtsgutsverletzung, die Beweggründe des Täters sowie dessen Vorleben und persönliche Verhältnisse. Das Vermögen des Opfers ist kein gesetzlich vorgesehener Faktor. Das Gericht würdigt alle relevanten Umstände bei der konkreten Strafbemessung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Ausmass der Rechtsgutsverletzung ist zentraler Faktor (Art. 47 StGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Beweggründe fliessen in die Strafzumessung ein.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Vorleben und persönliche Verhältnisse werden berücksichtigt.' }, { feld: 'optionen', id: 'opt-3', text: 'Das Opfervermögen ist keine Strafzumessungsregel — irrelevant nach Art. 47 StGB.' } ] },
  { id: '4373521d-2e94-4d9d-8504-d16819e7aeee', fachbereich: 'Recht', musterlosung: 'Nach Art. 8 ZGB trägt die Beweislast, wer aus einer Tatsache Rechte ableitet. Jan möchte den Kaufpreis zurückfordern und stützt sich dabei auf einen Sachmangel (Fälschung statt Original). Also muss Jan die Fälschung beweisen, typischerweise durch ein Kunstgutachten. Diese Beweislastverteilung ist für Käufer oft herausfordernd.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Verkäufer muss seine Geldverwendung nicht beweisen — irrelevant.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Jan trägt die Beweislast für den Mangel (Art. 8 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht der Verkäufer muss Echtheit beweisen — die Beweislast folgt dem Rechtsschutzbegehren.' }, { feld: 'optionen', id: 'opt-3', text: 'Das Gericht entscheidet nicht nach freiem Ermessen — es folgt der Beweislastregel.' } ] },
  { id: '443a23d8-a8c5-421b-8443-ad2a2ef2499b', fachbereich: 'Recht', musterlosung: 'Bei Straftatenkonkurrenz sieht Art. 49 StGB eine Strafschärfung vor: Das Gericht kann den Strafrahmen der schwersten Tat um maximal 50% erhöhen. Die gesetzliche Höchststrafe nach Art. 40 StGB (20 Jahre Freiheitsstrafe) bleibt unberührt. Eine Kumulation aller Einzelstrafen («Strafaddition») gibt es im Schweizer Recht nicht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Falsch — alle Delikte werden verurteilt, nicht nur das schwerste.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Erhöhung des Strafrahmens um max. 50%, Höchststrafe nach Art. 40 StGB bleibt.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Einzelbestrafung und Kumulation — das Schweizer Recht kennt Schärfung.' }, { feld: 'optionen', id: 'opt-3', text: 'Addition ist im Schweizer Strafrecht nicht vorgesehen.' } ] },
  { id: '444dafcb-56cb-420a-948e-3c8614fd522f', fachbereich: 'Recht', musterlosung: 'In Variante 1 (Herzinfarkt) liegt ein natürlicher Todesfall ohne Fremdeinfluss vor — kein strafrechtlicher Tatbestand. In Variante 2 (Vergiftung durch Ehepartnerin) sind die TBM von Art. 112 StGB (Mord) erfüllt: Tötung, vorsätzlich, mit besonders verwerflichem Zweck (Eliminationsmord). Rechtsfolge wäre lebenslängliche Freiheitsstrafe oder mindestens 10 Jahre.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Variante 1 natürlich, Variante 2 Art. 112 StGB (Mord).' }, { feld: 'optionen', id: 'opt-1', text: 'Einordnung ist bereits vorher möglich — der Sachverhalt wird vor Urteilsschluss bewertet.' }, { feld: 'optionen', id: 'opt-2', text: 'Ein natürlicher Tod ist nicht strafrechtlich relevant — nur Tötung durch Fremdhand.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 111 (vorsätzl. Tötung) wäre Grundtatbestand — Art. 112 (Mord) ist qualifiziert.' } ] },
  { id: '448cecbc-905f-4731-9c76-630afd717828', fachbereich: 'Recht', musterlosung: 'Die Vereinigung nach OR 118 tritt ein, wenn Gläubiger und Schuldner einer Obligation in derselben Person zusammenfallen — typisch durch Erbfolge oder Fusion. Da man sich selbst nichts schulden kann, erlischt die Obligation automatisch. Die Rechtsfolge tritt ohne Zutun der Parteien ein.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Gläubiger- und Schuldnerstellung in einer Person — Obligation erlischt.' }, { feld: 'optionen', id: 'opt-1', text: 'Unternehmensfusion kann Folge sein — der Rechtsbegriff ist enger gefasst.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein neuer Vertragsschluss — im Gegenteil: Obligation endet.' }, { feld: 'optionen', id: 'opt-3', text: 'Das wäre Verrechnung oder Novation — nicht Vereinigung.' } ] },
  { id: '44eac450-1e28-4122-b6d7-1d32fe0e7cc0', fachbereich: 'Recht', musterlosung: 'Nach Art. 262 Abs. 2 OR darf der Vermieter die Zustimmung zur Untermiete nur aus drei Gründen verweigern: (1) Der Mieter gibt die Bedingungen nicht offen, (2) die Bedingungen sind missbräuchlich (z.B. überhöhter Untermietzins), (3) dem Vermieter entstehen wesentliche Nachteile. Die Nationalität des Untermieters ist kein zulässiger Ablehnungsgrund.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Offenlegung der Untermiet-Bedingungen ist Pflicht.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Missbräuchliche Bedingungen (z.B. überhöhter Untermietzins) berechtigen zur Ablehnung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Wesentliche Nachteile für den Vermieter sind Verweigerungsgrund.' }, { feld: 'optionen', id: 'opt-3', text: 'Nationalität ist diskriminierend — kein zulässiger Grund.' } ] },
  { id: '458339c7-84ce-458f-a80c-20190286efd9', fachbereich: 'Recht', musterlosung: 'Das Eigentum wirkt nach Art. 641 ZGB nur «innerhalb der Schranken der Rechtsordnung». Eingeschränkt wird es durch öffentlich-rechtliche Vorschriften (Bau- und Zonenordnung, Umweltschutz), privatrechtliche Normen (Nachbarrecht, Art. 684 ZGB) und Rechtsgeschäfte (Dienstbarkeiten, Pfandrechte, Vermietung). Ein blosser Wunsch des Nachbarn genügt dagegen nicht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Bau- und Zonenordnung, Umweltschutz beschränken Eigentum.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Nachbarrecht (Art. 684 ZGB) verlangt Rücksichtnahme.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Freiwillige Einschränkungen durch Rechtsgeschäfte.' }, { feld: 'optionen', id: 'opt-3', text: 'Ein Wunsch begründet keine Rechtspflicht — nur Recht kann Eigentum einschränken.' } ] },
  { id: '46555822-e7d4-4bc6-b8a7-655c5819ffc0', fachbereich: 'Recht', musterlosung: 'Verfassungsänderungen unterliegen in der Schweiz dem obligatorischen Referendum (Art. 140 BV). Sie benötigen die Zustimmung der Mehrheit des Volkes (Volksmehr) und der Kantone (Ständemehr). Dieses doppelte Mehr sichert die föderale Legitimation von Verfassungsänderungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das Bundesgericht setzt Gesetze um — es ändert keine Verfassung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Volk und Stände müssen beide zustimmen (doppeltes Mehr).' }, { feld: 'optionen', id: 'opt-2', text: 'Das Parlament kann Verfassungsänderungen vorbereiten — aber nicht beschliessen.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Bundesrat schlägt vor oder führt aus — beschliesst nicht allein.' } ] },
  { id: '467d8340-b571-4c02-a7b5-5f6c2f8930aa', fachbereich: 'Recht', musterlosung: 'Das Obligationenrecht (OR) gehört zum Privatrecht — es regelt Beziehungen zwischen gleichberechtigten Rechtssubjekten (Kauf, Miete, Arbeit). Strafrecht, Verwaltungsrecht und Prozessrecht gehören dagegen zum öffentlichen Recht: der Staat tritt dem Bürger mit hoheitlicher Gewalt gegenüber.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: OR regelt Beziehungen zwischen gleichberechtigten Privaten.' }, { feld: 'optionen', id: 'opt-1', text: 'Prozessrecht ist öffentliches Recht — staatliche Verfahrensordnung.' }, { feld: 'optionen', id: 'opt-2', text: 'Strafrecht ist öffentliches Recht — staatliches Gewaltmonopol.' }, { feld: 'optionen', id: 'opt-3', text: 'Verwaltungsrecht ist öffentliches Recht — staatliches Verwaltungshandeln.' } ] },
  { id: '468ca0cc-3665-4e63-b5ad-6eb39cdc31d5', fachbereich: 'Recht', musterlosung: 'Bei zweiseitigen Verträgen kann der Gläubiger nach fruchtloser Nachfrist (OR 107) drei Wege wählen: Beharren auf Erfüllung plus Verspätungsschaden, Verzicht auf Leistung mit Schadenersatz wegen Nichterfüllung (positives Interesse) oder Rücktritt mit Rückabwicklung plus Schadenersatz (OR 109). Die Wahl ist vom Gläubiger zu treffen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Beharren + SE, Verzicht + SE oder Rücktritt + SE (OR 107/109).' }, { feld: 'optionen', id: 'opt-1', text: 'Die Nachfrist ist schon abgelaufen — neue Verlängerung ist nicht das Wahlrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Unvollständig — drei Varianten stehen zur Auswahl.' }, { feld: 'optionen', id: 'opt-3', text: 'Rücktritt ist nur eine von drei Optionen.' } ] },
  { id: '4692c142-532d-41d9-a762-9e38a050a960', fachbereich: 'Recht', musterlosung: 'Der Zeitwert berücksichtigt Alter und normale Abnutzung eines Gegenstands. Bei einem Schaden muss der Mieter nur den Zeitwert ersetzen — nicht den Neuwert. Die paritätische Lebensdauertabelle gibt Anhaltspunkte: Hat ein Wandanstrich eine Lebensdauer von 8 Jahren und ist 5 Jahre alt, trägt der Mieter nur 3/8 der Neustreichkosten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Alter und normale Abnutzung werden berücksichtigt.' }, { feld: 'optionen', id: 'opt-1', text: 'Der Marktwert des Mietobjekts ist eine andere Grösse.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Neuwert gilt nicht — das wäre ungerechtfertigte Bereicherung des Vermieters.' }, { feld: 'optionen', id: 'opt-3', text: 'Versicherungswerte folgen anderer Berechnung — nicht Zeitwert im Mietrecht.' } ] },
  { id: '46a1eaad-c0a8-441a-94d3-0fc2c65af2d4', fachbereich: 'Recht', musterlosung: 'Nach OR 62 entsteht eine ungerechtfertigte Bereicherung, wenn jemand ohne gültigen Rechtsgrund, aus einem nicht verwirklichten oder nachträglich weggefallenen Rechtsgrund bereichert wurde. Auch die Eingriffsbereicherung (unrechtmässige Nutzung fremden Eigentums) fällt darunter. Der Bereicherte muss die Bereicherung zurückerstatten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Zahlung ohne Rechtsgrund — klassischer Fall.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Rechtsgrund tritt nie ein (z.B. Bedingung fällt weg).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Rechtsgrund entfällt nachträglich (z.B. Rückabwicklung).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Eingriffsbereicherung durch Nutzung fremden Eigentums.' } ] },
  { id: '47109110-e0b2-426c-ae67-5c4226d4b636', fachbereich: 'Recht', musterlosung: 'Eine Massnahme (Art. 59–61 StGB) setzt voraus, dass die herkömmliche Strafe für den Täter ungeeignet ist und der Täter behandlungsbedürftig und -fähig ist (z.B. psychische Störung, Suchterkrankung). Die Dauer richtet sich nicht am Verschulden, sondern am Gesundheitszustand und am Sicherheitsbedürfnis der Allgemeinheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Ungeeignete Strafe + Behandlungsbedarf/-fähigkeit als Grundvoraussetzung.' }, { feld: 'optionen', id: 'opt-1', text: 'Minderjährigkeit führt ins Jugendstrafrecht — nicht Massnahme im StGB-Sinn.' }, { feld: 'optionen', id: 'opt-2', text: 'Deliktsschwere allein begründet keine Massnahme — der Täter muss behandlungsfähig sein.' }, { feld: 'optionen', id: 'opt-3', text: 'Opferwünsche sind nicht ausschlaggebend.' } ] },
  { id: '49e1d706-8ef8-425c-aa7f-0d549c14c308', fachbereich: 'Recht', musterlosung: 'Hier liegt ein rechtfertigender Notstand (Art. 17 StGB) vor. Zur Rettung eines höherwertigen Rechtsguts (Leib und Leben der Nachbarn) wird ein geringerwertiges Rechtsgut (Eigentum am Fenster) geschädigt. Da Leben und Gesundheit eindeutig höherwertig sind als Eigentum, ist die Sachbeschädigung gerechtfertigt — keine Strafbarkeit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine ausdrückliche Aufforderung nötig — Notstand wirkt ohne Einwilligung.' }, { feld: 'optionen', id: 'opt-1', text: 'Notwehr setzt Angreifer voraus — hier liegt Notstand (Art. 17 StGB) vor.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Notstand nach Art. 17 StGB — Leib und Leben über Eigentum.' }, { feld: 'optionen', id: 'opt-3', text: 'Sachbeschädigung kann durchaus gerechtfertigt sein (Notstand).' } ] },
  { id: '4a3c81cc-ae11-4f1f-8976-af616dd3d8db', fachbereich: 'Recht', musterlosung: 'Die Reinigungskraft (Schuldnerin) bietet ihre Leistung ordnungsgemäss an, kann sie aber nicht erbringen — nicht aus eigenem Verschulden, sondern weil der Gläubiger (Arbeitgeber) die Voraussetzungen nicht schafft (verschlossene Büros). Das ist Gläubigerverzug nach OR 91 ff. Der Gläubiger trägt die Risiken und muss Auslagen ersetzen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Leistung ist erbringbar — nicht unmöglich.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Schlechterfüllung — die Leistung wurde angeboten, nicht schlecht erbracht.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Reinigungskraft ist nicht in Verzug — sie wollte leisten.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gläubigerverzug — Annahmeverweigerung durch verschlossene Türen.' } ] },
  { id: '4a7f192b-a389-4173-86da-01accec56d72', fachbereich: 'Recht', musterlosung: 'Die Schweizer Grundrechte sind im zweiten Titel der Bundesverfassung in den Art. 7–36 unter der Überschrift «Grundrechte, Bürgerrechte und Sozialziele» verankert. Art. 7 schützt die Menschenwürde, Art. 35 bindet die staatlichen Behörden, Art. 36 regelt die Einschränkungsbedingungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 1–6 BV regeln allgemeine Bestimmungen, nicht Grundrechte.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Grundrechte stehen im 2. Titel BV, Art. 7–36.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 42–135 BV regeln Zuständigkeiten von Bund und Kantonen.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 136–142 BV regeln politische Rechte und Volksrechte.' } ] },
  { id: '4b0663b9-d6c6-4859-8cd1-6713e4b1eca5', fachbereich: 'Recht', musterlosung: 'Nach OR 64 muss der gutgläubig Bereicherte nur den Teil zurückerstatten, um den er im Zeitpunkt der Rückforderung noch bereichert ist. Hat er die Mittel verbraucht, reduziert sich der Rückerstattungsanspruch. Der bösgläubig Bereicherte muss dagegen den vollen Betrag erstatten, unabhängig vom aktuellen Zustand seines Vermögens.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Nur die Rest-Bereicherung ist rückzuerstatten (OR 64).' }, { feld: 'optionen', id: 'opt-1', text: 'Rückerstattungspflicht besteht — nur der Umfang ist eingeschränkt.' }, { feld: 'optionen', id: 'opt-2', text: 'Voller Betrag gilt für Bösgläubige, nicht für Gutgläubige.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Strafe — zivilrechtliche Rückerstattung ohne Verdopplung.' } ] },
  { id: '4b7aa024-47f4-43ef-b6ca-358e70b31581', fachbereich: 'Recht', musterlosung: 'Der Vermieter ist Eigentümer des Autos (Art. 641 ZGB). Nach Ablauf der Mietdauer hat der Mieter keinen Rechtstitel mehr, das Fahrzeug zu behalten — er hält es ohne rechtlichen Grund zurück. Der Eigentümer kann die Herausgabe der Sache mit der Vindikationsklage (Art. 641 Abs. 2 ZGB) durchsetzen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'OR 41 (Schadenersatz) setzt Widerrechtlichkeit + Schaden voraus — primär Herausgabe.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Vindikationsklage nach Art. 641 Abs. 2 ZGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Ende des Mietvertrags ändert nichts am Eigentum — es begründet gerade den Anspruch.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein Ersatzanspruch — der Eigentümer will die Sache zurück.' } ] },
  { id: '4bb6eb6c-c52f-43b6-abfe-70a6d4cc0b88', fachbereich: 'Recht', musterlosung: 'Hans ist 30 Jahre alt und damit mündig (Art. 14 ZGB). Er ist gesund, also urteilsfähig (Art. 16 ZGB). Damit erfüllt er beide Voraussetzungen der Handlungsfähigkeit nach Art. 13 ZGB. Er kann Rechtsgeschäfte wie einen Motorradkauf selbständig und ohne Zustimmung Dritter abschliessen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Schriftform ist beim Kaufvertrag über ein Motorrad nicht zwingend — Mündlichkeit genügt.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Ehefrau muss einem Autokauf nicht zustimmen — Hans entscheidet selbst.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Hans ist mündig und urteilsfähig, also handlungsfähig (Art. 13 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Bewilligung nötig — normaler Kaufvertrag.' } ] },
  { id: '4d034da9-4678-46c5-b295-3079fe8f4979', fachbereich: 'Recht', musterlosung: 'Es liegen zwei Mängel vor: Erstens die Formverletzung, da Kündigungen schriftlich erfolgen müssen (OR 335). Zweitens die fristlose Kündigung per sofort ohne wichtigen Grund (OR 337). Eine fristlose Kündigung ist nur bei erheblichen Gründen (schwere Pflichtverletzung) zulässig. Ohne solchen Grund wäre eine ordentliche Kündigung mit Frist erforderlich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Falsch — zwei Rechtsverletzungen liegen vor.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Formlosigkeit + vermutlich fehlender wichtiger Grund.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nur Grund — auch die Form ist verletzt.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht nur Form — sondern auch der wichtige Grund fehlt.' } ] },
  { id: '4d39301f-e014-4842-a100-0e9a88557d09', fachbereich: 'Recht', musterlosung: 'Die Sachenrechte gliedern sich traditionell in drei Kategorien: das Eigentum als umfassendstes dingliches Recht, die beschränkt dinglichen Rechte (Dienstbarkeiten, Pfandrechte, Grundlasten) sowie den Besitz als tatsächliche Gewalt über eine Sache. Diese Dreiteilung strukturiert das 4. Buch des ZGB.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Miete/Pacht sind Obligationenrecht — nicht Sachenrecht.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Eigentum, beschränkt dingliche Rechte, Besitz.' }, { feld: 'optionen', id: 'opt-2', text: 'Das wären Unterkategorien des Eigentums — nicht die Grundeinteilung.' }, { feld: 'optionen', id: 'opt-3', text: 'Forderungen gehören nicht zum Sachenrecht — sie sind Obligationen.' } ] },
  { id: '4d8c014c-d83a-4622-a97d-4a69a0ce9993', fachbereich: 'Recht', musterlosung: 'Videoüberwachung durch den Vermieter ist datenschutzrechtlich problematisch. Das DSG verlangt Verhältnismässigkeit, vorgängige Information der Betroffenen und Schutz der Privatbereiche (Wohnungszugang, Balkon). Die Kamera am Zugang zur Wohnung von Herrn Brunner erfüllt diese Voraussetzungen nicht. Er kann Entfernung oder Neuausrichtung verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Polizei — auch Private dürfen unter strengen Voraussetzungen überwachen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Verhältnismässigkeit + Information + Schutz der Privatbereiche fehlen.' }, { feld: 'optionen', id: 'opt-2', text: 'Keineswegs jederzeit — Datenschutz setzt klare Grenzen.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht generell verboten — aber nur unter datenschutzrechtlichen Voraussetzungen zulässig.' } ] },
  { id: '4e210e0b-2557-4153-9532-b4546fe262a2', fachbereich: 'Recht', musterlosung: 'Die gesetzliche Kündigungsfrist beträgt bei Geschäftsräumen nach Art. 266d OR sechs Monate. Bei Wohnungen sind es nach Art. 266c OR drei Monate, bei möblierten Zimmern und Parkplätzen nach Art. 266e OR zwei Wochen. Die Fristen schützen die Vertragsparteien und berücksichtigen den Charakter der Mietsache.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '1 Monat wäre viel zu kurz für Geschäftsräume — Geschäftsverlegung braucht Zeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: 6 Monate bei Geschäftsräumen nach Art. 266d OR.' }, { feld: 'optionen', id: 'opt-2', text: '3 Monate gelten für Wohnungen, nicht Geschäftsräume.' }, { feld: 'optionen', id: 'opt-3', text: '12 Monate sieht das Gesetz für Mietverhältnisse nicht vor.' } ] },
  { id: '4e4305dc-0312-4610-8c1d-dcb52a1a0be4', fachbereich: 'Recht', musterlosung: 'Nach Art. 8 ZGB trägt die Beweislast, wer aus einer Tatsache Rechte ableitet. Der Käufer muss die rechtzeitige Mängelrüge beweisen; der Ehegatte die Herkunft des Eigenguts aus Erbschaft; die Arbeitgeberin den wichtigen Grund für fristlose Kündigung. Bei Vertragsverschulden kehrt OR 97 die Beweislast um — dort muss der Schuldner beweisen, dass ihn kein Verschulden trifft.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Käufer leitet Rechte ab, muss Mängelrüge beweisen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Ehegatte leitet Eigengut-Anspruch ab, muss die Herkunft beweisen.' }, { feld: 'optionen', id: 'opt-2', text: 'Bei Vertragsverschulden kehrt OR 97 die Beweislast um — Schuldner muss Entlastung beweisen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Arbeitgeberin leitet fristlose Kündigung ab, muss wichtigen Grund beweisen.' } ] },
  { id: '500ce113-98a7-427e-a3d0-4c630327cad8', fachbereich: 'Recht', musterlosung: 'Das Wohnrecht (Art. 776 ff. ZGB) ist ein persönliches Recht, eine Wohnung zu bewohnen. Beim Tod des Eigentümers geht das Eigentum an die Erben; die wohnberechtigte Lebensgefährtin kann aber bis zu ihrem Tod in der Wohnung bleiben. Das Recht ist untrennbar mit ihrer Person verbunden — weder übertragbar noch vererblich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das Wohnrecht verschafft kein Eigentum — nur Wohnnutzung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Erben werden Eigentümer, Lebensgefährtin darf bleiben.' }, { feld: 'optionen', id: 'opt-2', text: 'Pflegeheimumzug beendet das Wohnrecht nicht automatisch — freiwilliger Verzicht möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Erben können das Wohnrecht nicht einseitig aufheben — es ist mit Eintrag im Grundbuch gesichert.' } ] },
  { id: '507ccbd0-a901-459e-ae23-7cdaa6ff9c1a', fachbereich: 'Recht', musterlosung: 'Die Verordnung zum Strassenverkehrsgesetz legt den Grenzwert bei 0,5 Promille fest. Ab diesem Wert gilt Fahrunfähigkeit wegen Angetrunkenheit als erwiesen (absoluter Grenzwert). Ab 0,8 Promille wird die Trunkenheit als qualifiziert eingestuft und als Vergehen im Strafregister eingetragen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '0,8 Promille ist die Grenze der qualifizierten Trunkenheit, nicht der einfachen.' }, { feld: 'optionen', id: 'opt-1', text: '0,0 Promille gilt für Neulenker und Berufsfahrer — nicht allgemein.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 0,5 Promille ist der allgemeine Grenzwert (absolute Fahrunfähigkeit).' }, { feld: 'optionen', id: 'opt-3', text: '1,0 Promille wäre schon deutlich in der qualifizierten Zone.' } ] },
  { id: '50d5eeed-8be1-4010-991b-5d5d1d15b46c', fachbereich: 'Recht', musterlosung: 'Die COVID-19-Massnahmen griffen in zahlreiche Grundrechte ein: Versammlungsfreiheit (Art. 22) durch Versammlungsverbote, Wirtschaftsfreiheit (Art. 27) durch Geschäftsschliessungen, persönliche Freiheit (Art. 10) durch Bewegungseinschränkungen und Glaubensfreiheit (Art. 15) durch Gottesdienstverbote. Die Massnahmen wurden per Notverordnung des Bundesrates erlassen und später gesetzlich verankert.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Versammlungsverbote griffen in Art. 22 BV ein.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Geschäftsschliessungen betrafen die Wirtschaftsfreiheit (Art. 27 BV).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Bewegungseinschränkungen und Quarantäne berührten Art. 10 BV.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Verbot von Gottesdiensten verletzte temporär Art. 15 BV.' } ] },
  { id: '51689750-3759-4c66-beff-6cd22e8fa765', fachbereich: 'Recht', musterlosung: 'Subsumtion bedeutet die Anwendung abstrakter Gesetzesnormen auf einen konkreten Sachverhalt. Dabei wird geprüft, ob die Tatbestandsmerkmale der Norm im Fall erfüllt sind. Falls ja, tritt die Rechtsfolge ein. Die Subsumtion ist der Kern juristischer Falllösung und folgt dem Schema: Obersatz — Voraussetzungen — Subsumtion — Schlussfolgerung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das wäre ein Rechtsmittel (Berufung, Beschwerde) — nicht Subsumtion.' }, { feld: 'optionen', id: 'opt-1', text: 'Zusammenfassung ist Zusammenfassen, nicht Subsumtion.' }, { feld: 'optionen', id: 'opt-2', text: 'Gesetzgebung ist Aufgabe des Parlaments — nicht Subsumtion.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Abstrakte Norm auf konkreten Sachverhalt anwenden.' } ] },
  { id: '52a02486-5035-426d-8833-348af5642b95', fachbereich: 'Recht', musterlosung: 'OR 336c enthält eine absolute Kündigungssperre: Während der Schwangerschaft und in den 16 Wochen nach der Niederkunft darf der Arbeitgeber nicht kündigen. Diese Sperrfrist schützt Mutter und Kind umfassend und gilt unabhängig vom Kündigungsgrund. Eine dennoch ausgesprochene Kündigung ist nichtig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Schwangerschaft + 16 Wochen nach Geburt — absolute Sperrfrist.' }, { feld: 'optionen', id: 'opt-1', text: 'Es besteht sehr wohl Kündigungsschutz — OR 336c.' }, { feld: 'optionen', id: 'opt-2', text: 'Sperrfrist gilt für gesamte Schwangerschaft, nicht nur erste 3 Monate.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Schutz endet nach 16 Wochen post partum — danach wieder reguläre Regeln.' } ] },
  { id: '53506dbb-d4fd-4626-a96b-58e11423bfb6', fachbereich: 'Recht', musterlosung: 'Die Schweiz kennt die indirekte Drittwirkung der Grundrechte: Der Gesetzgeber muss Gesetze erlassen, die den Schutz der Grundrechte auch im Verhältnis zwischen Privaten sicherstellen. Beispiel: Das Arbeitsrecht (Art. 328 OR) schützt die Persönlichkeit der Arbeitnehmenden. Eine direkte Drittwirkung (Grundrechte wirken unmittelbar zwischen Privaten) ist die Ausnahme.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Direkte unmittelbare Drittwirkung ist in der Schweiz die Ausnahme, nicht die Regel.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Der Gesetzgeber schafft privatrechtliche Schutznormen (indirekte Drittwirkung).' }, { feld: 'optionen', id: 'opt-2', text: 'Grundrechte richten sich gegen den Staat — das ist Abwehrdimension, nicht Drittwirkung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Arbeitsrecht (Art. 328 OR) als Beispiel indirekter Drittwirkung.' } ] },
  { id: '5451d66e-b2ae-45bd-9700-02f65313a1d1', fachbereich: 'Recht', musterlosung: 'Ein verstopfter Abfluss, der mit einem Saugnapf behoben werden kann, ist gewöhnlicher Unterhalt nach Art. 259 OR. Solche kleinen Mängel muss der Mieter selbst beheben — er muss nicht den Vermieter einschalten. Erst bei grösseren Mängeln (defekte Heizung, undichtes Dach) trifft den Vermieter eine Handlungspflicht (Art. 259a ff. OR).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Hinterlegung bei gewöhnlichem Unterhalt ist nicht zulässig — die Pflicht trifft den Mieter.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Gewöhnlicher Unterhalt (Art. 259 OR) — Sarah repariert selbst.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Vermietereinsatz bei Kleinigkeiten — Abfluss ist gewöhnlicher Unterhalt.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine fristlose Kündigung bei einem kleinen Mangel — unverhältnismässig.' } ] },
  { id: '555c847d-bf25-48be-8797-f4d16d77b351', fachbereich: 'Recht', musterlosung: 'Eine Pergola ist eine nützliche bauliche Massnahme (Art. 647d ZGB). Dafür braucht es die Mehrheit aller Miteigentümer, die zugleich die Mehrheit der Wertquoten halten. Bei Stockwerkeigentum zählt die Gesamtzahl aller Stimmberechtigten — nicht nur Anwesende. 6 von 12 Eigentümern (keine Kopfmehrheit) und 450/1000 Wertquoten (unter der Hälfte) — der Bau ist nicht beschlossen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Pergola ist nützlich, nicht luxuriös — keine Einstimmigkeit nötig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Weder Kopf- noch Quotenmehrheit erreicht.' }, { feld: 'optionen', id: 'opt-2', text: 'Wertquoten unter 50% — keine Mehrheit.' }, { feld: 'optionen', id: 'opt-3', text: 'Anwesendenmehrheit reicht nicht — alle Stimmberechtigten zählen.' } ] },
  { id: '560c11f9-48d9-4fbe-bf83-5a189717233f', fachbereich: 'Recht', musterlosung: 'Im Zivilprozess gilt die Verhandlungsmaxime: Der Richter befasst sich nur mit den von den Parteien vorgebrachten und bewiesenen Tatsachen. Sind sich die Parteien einig, können sie dem Richter Tatsachen vorenthalten. Der Richter berücksichtigt von sich aus nur notorische Tatsachen (allgemein bekannte Fakten).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Parteien können einigen Tatsachen übergehen, nur notorische zählt der Richter selbst.' }, { feld: 'optionen', id: 'opt-1', text: 'Prozess wird nicht eingestellt — die Verhandlungsmaxime gilt.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Amtsermittlung — anders als im Strafprozess.' }, { feld: 'optionen', id: 'opt-3', text: 'Sachverständige werden nur auf Antrag beigezogen — nicht von Amtes wegen.' } ] },
  { id: '56474e90-8882-453f-8a02-6b0ab69edf92', fachbereich: 'Recht', musterlosung: 'Das Sachenrecht regelt die Rechte, welche Rechtssubjekte (natürliche und juristische Personen) an Rechtsobjekten (Sachen) haben. Es ist neben dem Obligationenrecht das zentrale Vermögensrecht. Das Obligationenrecht regelt dagegen, wer gegenüber wem welche Leistung verlangen kann — es wirkt nur inter partes.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Rechte an Sachen sind Kerngegenstand des Sachenrechts.' }, { feld: 'optionen', id: 'opt-1', text: 'Haftung bei Sachbeschädigung ist OR — nicht Sachenrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Geistiges Eigentum regeln URG/PatG — nicht das klassische Sachenrecht.' }, { feld: 'optionen', id: 'opt-3', text: 'Kaufverträge regelt das OR — nicht das Sachenrecht.' } ] },
  { id: '56e49849-29e5-474c-94d1-4d9bb552d788', fachbereich: 'Recht', musterlosung: 'Der Vermieter darf nur Angaben verlangen, die für die Mieterauswahl nach objektiven Kriterien nötig sind. Fragen zu Krankheiten, Mitgliedschaften in Mieterschutzorganisationen oder politischen Parteien sind unzulässig. Die ungefähre Einkommenshöhe darf erfragt werden — sie ist relevant für die Zahlungsfähigkeit. Grundlage ist das DSG und die EDÖB-Richtlinien.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Mieterschutz-Mitgliedschaft ist irrelevant und unzulässig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Krankheiten sind besonders schützenswerte Gesundheitsdaten.' }, { feld: 'optionen', id: 'opt-2', text: 'Zulässig — Einkommen ist relevant für Zahlungsfähigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Politische Mitgliedschaft unterliegt besonderem Datenschutz.' } ] },
  { id: '571b2a8e-0f92-43f1-9326-732fc0b60e51', fachbereich: 'Recht', musterlosung: 'OR 127 legt die allgemeine Verjährungsfrist auf 10 Jahre fest. Spezialgesetze können kürzere Fristen vorsehen (z.B. 5 Jahre für periodisch wiederkehrende Leistungen, OR 128; 1 Jahr für Mietmängel). Nach Verjährung besteht die Forderung zwar weiter, der Schuldner kann die Erfüllung aber verweigern.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '20 Jahre sieht das OR nicht als allgemeine Frist vor.' }, { feld: 'optionen', id: 'opt-1', text: '3 Jahre gilt z.B. im Deliktsrecht (OR 60), nicht als allgemeine Frist.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: OR 127 — allgemeine Verjährungsfrist 10 Jahre.' }, { feld: 'optionen', id: 'opt-3', text: '5 Jahre ist eine Spezialfrist (OR 128), nicht die allgemeine.' } ] },
  { id: '57bac55a-ab62-47e8-b1ff-4d98ac05e7c6', fachbereich: 'Recht', musterlosung: 'Zum öffentlichen Recht gehören Völkerrecht (Beziehungen zwischen Staaten) und das Schuldbetreibungs- und Konkursrecht (zwangsweise Eintreibung durch staatliche Behörden — Betreibungsamt). Kaufverträge zwischen Privatpersonen und die Bestimmungen zu Eigentum und Besitz sind hingegen klassisches Privatrecht (OR, Sachenrecht).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Völkerrecht regelt Staat zu Staat — öffentliches Recht.' }, { feld: 'optionen', id: 'opt-1', text: 'Kaufvertrag zwischen Privaten ist Privatrecht (OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: SchKG wird von staatlichen Behörden (Betreibungsamt) vollzogen.' }, { feld: 'optionen', id: 'opt-3', text: 'Eigentum und Besitz sind Privatrecht — Sachenrecht im ZGB.' } ] },
  { id: '5906faa3-a7de-4474-843b-4ee5271e413f', fachbereich: 'Recht', musterlosung: 'Das Bundesgericht erkannte, dass die Wegweisungen in die Versammlungsfreiheit (Art. 22 BV) eingreifen, weil die Betroffenen gemeinsam im öffentlichen Raum (Bahnhof) verweilten. Einige Richter sahen zusätzlich einen Eingriff in die persönliche Freiheit (Art. 10 BV). Der Eingriff galt als nicht sehr schwer, da die Betroffenen weiterhin Züge nehmen und einkaufen konnten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Meinungsäusserungsfreiheit war nicht zentral — es ging um Aufenthalt, nicht Äusserung.' }, { feld: 'optionen', id: 'opt-1', text: 'Eigentumsgarantie war nicht betroffen — keine Vermögensposition.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Versammlungsfreiheit (Art. 22) + teilweise persönliche Freiheit (Art. 10).' }, { feld: 'optionen', id: 'opt-3', text: 'Niederlassungsfreiheit betrifft den Wohnsitz — nicht Aufenthalt im Bahnhof.' } ] },
  { id: '59c57d13-7e21-4c04-be09-8880426af522', fachbereich: 'Recht', musterlosung: 'Nach OR 68 muss der Schuldner die Obligation grundsätzlich selbst erfüllen — aber nur dann persönlich, wenn es auf seine Person ankommt (z.B. Arztleistung, Künstlervertrag). Bei vertretbaren Leistungen (z.B. Geldschuld, Warenlieferung) kann auch ein Dritter mit befreiender Wirkung erfüllen. Der Gläubiger muss solche Drittleistungen akzeptieren.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Schuldner, aber nicht zwingend persönlich — Drittleistung bei Vertretbarkeit möglich.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht jeder Dritte — der Schuldner bleibt Verpflichteter.' }, { feld: 'optionen', id: 'opt-2', text: 'Persönliche Erfüllung ist nur bei höchstpersönlichen Leistungen Pflicht.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Gläubiger bestimmt nicht — das OR regelt es.' } ] },
  { id: '5a31e27d-2b48-4b4c-bb16-0131778075de', fachbereich: 'Recht', musterlosung: 'Bürgerliche und politische Rechte (1. Dimension) sind Abwehrrechte gegen den Staat: Leben, Freiheit, Meinungsäusserung, politische Teilhabe. Wirtschaftliche, soziale und kulturelle Rechte (2. Dimension) sind Leistungsansprüche: Arbeit, Bildung, soziale Sicherheit. Die 1. Dimension ist älter und universell anerkannt, die 2. Dimension verlangt staatliche Aufwendungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Meinungsfreiheit (Art. 19 AEMR) ist bürgerlich-politisch (1. Dimension).' }, { feld: 'optionen', id: 'opt-1', text: 'Recht auf Arbeit ist wirtschaftlich-sozial (2. Dimension).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Leben und Freiheit (Art. 3 AEMR) sind 1. Dimension — klassisch bürgerlich.' }, { feld: 'optionen', id: 'opt-3', text: 'Bildung ist kulturell-sozial (2. Dimension).' } ] },
  { id: '5a3ebf2f-0246-4890-9d98-4eed9f5d08c1', fachbereich: 'Recht', musterlosung: 'Bei jungen Erwachsenen (Art. 61 StGB) orientiert sich eine Massnahme nicht am Verschulden, sondern am Behandlungsbedarf. Ziel ist die Vermittlung von Fähigkeiten für ein selbstverantwortliches Leben. Eine reine Freiheitsstrafe adressiert die zugrunde liegenden Probleme (gestörte Persönlichkeitsentwicklung) oft nicht. Die Rückfallgefahr sinkt langfristig stärker durch Resozialisierung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Massnahmen sind oft teurer, nicht günstiger — Kosten sind nicht der Grund.' }, { feld: 'optionen', id: 'opt-1', text: 'Massnahmen sind an Regeln gebunden — nicht Freibrief.' }, { feld: 'optionen', id: 'opt-2', text: 'Massnahmen können sogar länger dauern als Freiheitsstrafen — Dauer richtet sich nach Bedarf.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Behandlungsbedarf + Resozialisierung reduzieren Rückfallgefahr.' } ] },
  { id: '5be0b089-1e0f-40a8-82a0-2c6da5c04263', fachbereich: 'Recht', musterlosung: 'Im Zivilprozess läuft der Instanzenzug: Regionalgericht → Obergericht → Bundesgericht. Direkter Weg ans Bundesgericht ist ausgeschlossen. Sandro muss zuerst Berufung beim Obergericht des Kantons Bern einlegen. Erst nach dessen Urteil kann er mit der Beschwerde in Zivilsachen ans Bundesgericht gelangen — sofern die Streitwertgrenze erreicht ist.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein direkter Weg zum Bundesgericht — Instanzenzug ist einzuhalten.' }, { feld: 'optionen', id: 'opt-1', text: 'Schlichtung ist schon erledigt — sie kommt vor der Klage, nicht nach dem Urteil.' }, { feld: 'optionen', id: 'opt-2', text: 'Urteile des Regionalgerichts sind nicht endgültig — Berufung möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Berufung beim Obergericht als nächster Schritt.' } ] },
  { id: '5cd15692-bd49-4a8e-ba27-4a5cc060bd34', fachbereich: 'Recht', musterlosung: 'Die Unteilbarkeit der Menschenrechte bedeutet, dass bürgerliche, politische, wirtschaftliche, soziale und kulturelle Rechte gleichwertig sind und sich gegenseitig bedingen. Es wäre sinnlos, politische Rechte zu gewähren, wenn Zugang zu Bildung oder Nahrung fehlt. Alle Dimensionen gehören zusammen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Einteilung in Dimensionen ist durchaus üblich — Unteilbarkeit meint gleichwertige Geltung.' }, { feld: 'optionen', id: 'opt-1', text: 'Einzelne Rechte können schon durchgesetzt werden — nicht nur als Paket.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Alle Menschenrechte sind gleichwertig und gegenseitig bedingend.' }, { feld: 'optionen', id: 'opt-3', text: 'Unteilbarkeit betrifft nicht die individuelle Aufteilung, sondern die Kategorien.' } ] },
  { id: '5cff5f78-86b2-4a0d-8d4d-a1b810b44108', fachbereich: 'Recht', musterlosung: 'Tim wollte niemanden treffen — kein Vorsatz. Er hätte aber nach Treu und Glauben damit rechnen müssen, dass im Wald Menschen spazieren. Die Sorgfaltspflichtverletzung begründet Fahrlässigkeit (Art. 12 Abs. 3 StGB). Ein blosser Zufall liegt nicht vor, weil ein vernünftiger Mensch die Gefahr erkannt hätte.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Notwehr setzt Angreifer voraus — hier nicht vorhanden.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Fahrlässigkeit (Art. 12 Abs. 3 StGB) — Sorgfaltspflichtverletzung.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Vorsatz — Tim hat nicht absichtlich geworfen.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein Zufall — die Gefahr war vorhersehbar.' } ] },
  { id: '5d9b3921-7ef0-43c9-862a-edf7d1422aa4', fachbereich: 'Recht', musterlosung: 'Die ZPO anerkennt als Beweismittel: Urkunden (Art. 177 ZPO), Zeugenaussagen (Art. 169 ZPO), Augenschein (Art. 181 ZPO), Parteibefragung und Gutachten. Blosse Meinungen aus sozialen Medien sind kein eigenständiges Beweismittel; sie könnten allenfalls als Urkunde eingereicht werden, haben aber geringe Beweiskraft.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Urkunden wie Verträge und Quittungen sind zentrale Beweismittel.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Zeugenaussagen sind klassisches Beweismittel.' }, { feld: 'optionen', id: 'opt-2', text: 'Meinungen aus sozialen Medien sind kein eigenständiges Beweismittel.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Augenschein ermöglicht direkte richterliche Wahrnehmung.' } ] },
  { id: '5e70facd-09dd-4cda-897c-1d05d27fa408', fachbereich: 'Recht', musterlosung: 'Die staatlichen Zwangsmittel sind vielfältig: Im Zivilrecht erfolgt die Durchsetzung durch Realerfüllung oder Schadenersatz; im Strafrecht richten sich Zwangsmassnahmen gegen die Person (Freiheitsstrafe) oder das Vermögen (Geldstrafe, Busse). Nicht nur Freiheitsstrafen — der Strafkatalog bietet verschiedene Sanktionsformen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Zivilrechtliche Erfüllung erfolgt in natura oder per SE.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Strafrecht trifft Person oder Vermögen (Freiheitsstrafe/Geldstrafe).' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — nicht nur Freiheitsstrafen, auch Geldstrafen und Bussen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Die Zwangsmittel sind vielfältig und differenziert.' } ] },
  { id: '5ef58150-3733-4c49-866f-27b88227127a', fachbereich: 'Recht', musterlosung: 'Art. 933 ZGB schützt den gutgläubigen Erwerber bei anvertrauten Sachen. Drei kumulative Tatbestandsmerkmale: (1) Der Eigentümer hat die Sache freiwillig einem Dritten anvertraut (geliehen, vermietet, verpfändet); (2) der Veräusserer war nicht zur Veräusserung ermächtigt; (3) der Erwerber ist gutgläubig. Erwerb bei öffentlicher Versteigerung ist kein TBM von Art. 933, sondern anderer Schutzgrund.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Freiwillige Überlassung durch Eigentümer (Anvertrauung).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Fehlende Ermächtigung des Veräusserers.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gutgläubigkeit des Erwerbers.' }, { feld: 'optionen', id: 'opt-3', text: 'Öffentliche Versteigerung ist kein TBM von Art. 933 — sie ist bei Art. 934 Abs. 2 relevant.' } ] },
  { id: '5f32b412-924e-40c8-9551-e839097191d6', fachbereich: 'Recht', musterlosung: 'Nach Art. 369 Abs. 1 StGB werden Freiheitsstrafen unter einem Jahr 10 Jahre nach Ablauf der gerichtlich zugemessenen Strafdauer von Amtes wegen aus dem Strafregister entfernt. Bei Strafen von 1–5 Jahren sind es 15 Jahre, bei Strafen ab 5 Jahren 20 Jahre. Der Eintritt erfolgt automatisch nach Fristablauf.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Einträge werden nach Fristablauf entfernt — nicht ewig.' }, { feld: 'optionen', id: 'opt-1', text: '15 Jahre gelten für Strafen von 1–5 Jahren — nicht unter 1 Jahr.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 10 Jahre nach Ablauf der Strafdauer bei Freiheitsstrafe unter 1 Jahr.' }, { feld: 'optionen', id: 'opt-3', text: '5 Jahre sieht das Gesetz nicht vor — zu kurz.' } ] },
  { id: '5f7e1573-540c-4fd9-b7aa-3da3f01289a0', fachbereich: 'Recht', musterlosung: 'Ein Fixgeschäft (OR 108) liegt vor, wenn die rechtzeitige Erfüllung für den Gläubiger wesentlich ist. Bei Verspätung wird die Leistung wertlos (z.B. Hochzeitstorte nach dem Hochzeitstag). Folgen: Der Gläubiger kann ohne Nachfristsetzung vom Vertrag zurücktreten und Schadenersatz wegen Nichterfüllung verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Rücktrittsrecht wird bei Fixgeschäften gerade erleichtert — keine Nachfrist nötig.' }, { feld: 'optionen', id: 'opt-1', text: 'Laufzeit ist nicht das Kriterium — Zeitkritikalität ist entscheidend.' }, { feld: 'optionen', id: 'opt-2', text: 'Fester Preis ist Fixpreisgeschäft — anderer Begriff.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Rechtzeitige Erfüllung ist wesentlich — Wertlosigkeit bei Verspätung.' } ] },
  { id: '5f9f00ef-ad59-4768-ae1d-ba7503cbac3a', fachbereich: 'Recht', musterlosung: 'Bei Willensmängeln (Irrtum, Täuschung, Furchterregung) ist der Vertrag anfechtbar: Er bleibt gültig, bis der Geschädigte ihn durch einseitige Erklärung als für sich unverbindlich erklärt. Ein Gericht muss nicht eingeschaltet werden. Die Anfechtung muss innert Jahresfrist seit Entdeckung (OR 31) erfolgen — sonst gilt der Vertrag als genehmigt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein Gericht nötig — einseitige Erklärung genügt.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine automatische Auflösung — der Geschädigte muss anfechten.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nichtig, sondern anfechtbar — das ist der Unterschied zu Art. 20 OR.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Einseitige Unverbindlichkeitserklärung durch den Geschädigten.' } ] },
  { id: '604b6ffc-3e36-4ee9-9922-6abdfa4ba793', fachbereich: 'Recht', musterlosung: 'Beim Leasing wird die Sache dem Leasingnehmer zum Gebrauch überlassen — das Eigentum verbleibt bei der Leasinggeberin. Hans Eugster hat die tatsächliche Gewalt über den Peugeot (Besitz nach Art. 919 ZGB) und ist unselbständiger Besitzer. Die Auto-Interleasing AG bleibt Eigentümerin (Art. 641 ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Leasing überträgt kein Eigentum — die Leasinggeberin bleibt Eigentümerin.' }, { feld: 'optionen', id: 'opt-1', text: 'Hans ist nicht Eigentümer — er least das Fahrzeug.' }, { feld: 'optionen', id: 'opt-2', text: 'Die AG besitzt das Auto nicht — Hans hat es in seiner Gewalt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Hans Besitzer (Art. 919), AG Eigentümerin (Art. 641).' } ] },
  { id: '607a0ca5-ca7a-4574-8697-4284d160dd7e', fachbereich: 'Recht', musterlosung: 'Jede Gesetzesnorm hat die Struktur «Wenn Tatbestand, dann Rechtsfolge». Art. 54 ZGB enthält zwei kumulative Tatbestandsmerkmale: (1) Es handelt sich um eine juristische Person und (2) die nach Gesetz und Statuten notwendigen Organe sind bestellt. Rechtsfolge: Die juristische Person ist handlungsfähig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Verdreht — Handlungsfähigkeit ist die Rechtsfolge, nicht TBM.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: TBM juristische Person + Organe; Rechtsfolge Handlungsfähigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsche Zuordnung — Organe bestellen ist TBM, nicht RF.' }, { feld: 'optionen', id: 'opt-3', text: 'Statuten sind Teil der TBM-Prüfung — nicht Folge einer Jur.-Personen-Qualität.' } ] },
  { id: '60e4de4d-652d-42b3-a972-270b37f0477c', fachbereich: 'Recht', musterlosung: 'Beim Augenschein (Art. 181 ZPO) verschafft sich das Gericht einen persönlichen, unmittelbaren Eindruck vom Streitgegenstand — z.B. durch Besichtigung einer Baustelle, eines Zauns oder einer Liegenschaft. Besonders geeignet bei Nachbarschaftsstreitigkeiten, Baumängeln oder Grenzstreitigkeiten. Unterschied zum Gutachten: Beim Augenschein betrachtet das Gericht selbst, beim Gutachten ein externer Sachverständiger.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Richterliche Besichtigung vor Ort — ideal bei Nachbarrecht und Baumängeln.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre eine Zeugenaussage — anderes Beweismittel.' }, { feld: 'optionen', id: 'opt-2', text: 'Das wäre ein Gutachten — nicht der Augenschein selbst.' }, { feld: 'optionen', id: 'opt-3', text: 'Fotos sind Urkunden — nicht Augenschein (der verlangt direkten Besuch).' } ] },
  { id: '60ed8d85-ca82-4472-a638-544e965d3305', fachbereich: 'Recht', musterlosung: 'Die Mängelrechte des Mieters sind in den Art. 259–259i OR geregelt: Vom kleinen Unterhalt (Art. 259) über Pflichten bei grösseren Mängeln (Art. 259a ff.) bis zur Hinterlegung des Mietzinses auf einem amtlichen Konto (Art. 259g–h). Diese Normen gewähren dem Mieter bei Mängeln Ersatzvornahme, Mietzinsreduktion, Schadenersatz und ggf. Kündigung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 266 ff. regeln die Beendigung — nicht Mängel.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 253–255 OR regelt Grundlagen der Miete — nicht Mängel.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Art. 259–259i OR regeln die Mängelrechte des Mieters.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 270 ff. regelt Mietzinsanfechtung — nicht Mängel.' } ] },
  { id: '63b57662-330f-44ff-b33c-c12cd06ff0ac', fachbereich: 'Recht', musterlosung: 'Beim Raub wird kein Eigentum übertragen — dazu bräuchte es einen gültigen Rechtsgrund (Art. 714 ZGB). Ottilie F. bleibt Eigentümerin der Handtasche mitsamt Inhalt. Der Mofafahrer hat allerdings die tatsächliche Herrschaft — er ist (unselbständiger) Besitzer. Ottilie kann die Handtasche mit Vindikation nach Art. 641 Abs. 2 ZGB herausverlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Formulierung ungenau — der Fragende meint umgekehrt: Ottilie bleibt Eigentümerin, Mofafahrer Besitzer.' }, { feld: 'optionen', id: 'opt-1', text: 'Raub überträgt kein Eigentum — es fehlt der Rechtsgrund.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Besitz geht verloren (Mofafahrer hat die Sache), das Eigentum bleibt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Mofafahrer Besitzer, Ottilie bleibt Eigentümerin.' } ] },
  { id: '63f203a6-26b1-4ebc-ac42-c5513a9231f9', fachbereich: 'Recht', musterlosung: 'Moral bezieht sich auf die innere Haltung — Werte und Überzeugungen des Einzelnen. Sitte betrifft die äussere Haltung — gesellschaftlich erwartetes Verhalten. Beide sind nicht staatlich erzwingbar; das unterscheidet sie vom Recht. Moral, Sitte und Recht überschneiden sich inhaltlich häufig, sind aber in Grundlage und Durchsetzung verschieden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Moral = innere Haltung, Sitte = äussere Haltung.' }, { feld: 'optionen', id: 'opt-1', text: 'Weder Moral noch Sitte werden staatlich durchgesetzt.' }, { feld: 'optionen', id: 'opt-2', text: 'Verdreht — Moral ist innere, Sitte äussere Haltung.' }, { feld: 'optionen', id: 'opt-3', text: 'Beide sind nicht erzwingbar — nur Recht hat staatliche Durchsetzung.' } ] },
  { id: '6495cb94-b241-46ad-84c9-937a3d013eb2', fachbereich: 'Recht', musterlosung: 'Nach Art. 8 ZGB trägt normalerweise die Beweislast, wer aus einer Tatsache Rechte ableitet. Art. 3 ZGB vermutet aber den guten Glauben — wer sich darauf beruft, muss ihn nicht beweisen. Die Gegenpartei muss vielmehr die Bösgläubigkeit beweisen. Das führt zur Beweislastumkehr: weg vom Berufenden, hin zum Bestreitenden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der gute Glaube kann grundsätzlich bewiesen werden — aber die Vermutung erleichtert die Position.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein automatischer Gewinn — der Richter prüft die Bösgläubigkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 8 gilt weiter — Art. 3 ist speziellere Regel mit Vermutung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Vermutung des guten Glaubens → Gegenpartei muss Bösgläubigkeit beweisen.' } ] },
  { id: '65af71e6-1a98-4d63-b0c2-180c8890ad00', fachbereich: 'Recht', musterlosung: 'Die Allgemeine Erklärung der Menschenrechte wurde am 10. Dezember 1948 von der UN-Generalversammlung als Resolution 217 A (III) verabschiedet. Sie ist rechtlich nicht bindend, aber moralisch und politisch enorm einflussreich. Der 10. Dezember wird seither weltweit als Tag der Menschenrechte begangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '1. August 1291 ist die mythische Gründung der Eidgenossenschaft — nicht AEMR.' }, { feld: 'optionen', id: 'opt-1', text: '26. Juni 1945 ist die Unterzeichnung der UN-Charta — nicht AEMR.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 10. Dezember 1948 — Resolution 217 A (III) der UN.' }, { feld: 'optionen', id: 'opt-3', text: '4. Juli 1776 ist die US-Unabhängigkeitserklärung — nicht AEMR.' } ] },
  { id: '65b7cb00-fecc-4139-9e1e-1410d40b047d', fachbereich: 'Recht', musterlosung: 'Die Erfüllung (OR 68) ist der häufigste Erlöschensgrund. Das Unmöglichwerden (OR 119) setzt voraus, dass die Leistung nachträglich und ohne Verschulden des Schuldners unmöglich wird. Die Verjährung löscht die Forderung nicht aus — sie bleibt bestehen, nur die Durchsetzung kann verweigert werden. Die Verrechnung (OR 120) erfolgt durch einseitige Erklärung ohne Zustimmung der Gegenseite.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Erfüllung (OR 68) ist der Regelfall des Erlöschens.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: OR 119 verlangt nachträgliche und unverschuldete Unmöglichkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Verjährung löscht die Forderung nicht — sie macht sie nur uneinbringbar.' }, { feld: 'optionen', id: 'opt-3', text: 'Verrechnung ist einseitig — keine Zustimmung der Gegenseite nötig.' } ] },
  { id: '65be3b21-ecb0-4573-baaa-05d68448d515', fachbereich: 'Recht', musterlosung: 'OR 190 stellt im kaufmännischen Verkehr zwei Vermutungen auf: Erstens, dass ein vereinbarter Verfalltag Fixgeschäftscharakter hat (OR 108 Ziff. 3). Zweitens, dass der Käufer bei Nichteinhaltung auf die nachträgliche Leistung verzichtet und Schadenersatz wegen Nichterfüllung verlangt (OR 107 Abs. 2). Der Käufer wird so besser geschützt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'OR 190 stellt ausdrücklich Vermutungen auf — allgemeine Regeln werden modifiziert.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein Nichtigkeitsvermutung — im Gegenteil, Schutz des Käufers.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Fixgeschäft + Leistungsverzicht + Schadenersatzanspruch.' }, { feld: 'optionen', id: 'opt-3', text: 'Umgekehrt — Käufer wird gerade von der Annahmepflicht entlastet.' } ] },
  { id: '65d1c34e-eefb-409d-8b97-10e2f2ee03e8', fachbereich: 'Recht', musterlosung: 'Persönliche Leistung (JStG 23) bedeutet, dass der Jugendliche gemeinnützige Arbeit verrichten oder einen Kurs besuchen muss, um sein Unrecht wiedergutzumachen. Beispiele: Strassen putzen, Sozialeinrichtung unterstützen, Antigewalttraining. Die Massnahme verbindet Wiedergutmachung mit erzieherischem Wert — sie soll beim Jugendlichen Verantwortungsbewusstsein entwickeln.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das wäre Schadenersatz oder Genugtuung — nicht persönliche Leistung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Arbeit oder Kurs zur Wiedergutmachung und Resozialisierung (JStG 23).' }, { feld: 'optionen', id: 'opt-2', text: 'Entschuldigung ist keine JStG-23-Massnahme — zu symbolisch.' }, { feld: 'optionen', id: 'opt-3', text: 'Aufsatz ist keine persönliche Leistung im Sinne von JStG 23.' } ] },
  { id: '65d5b78e-aa66-4891-ada3-2fa50b38d472', fachbereich: 'Recht', musterlosung: 'Die Verjährungsfrist im Strafrecht richtet sich nach der maximalen Strafe, die der Straftatbestand im besonderen Teil des StGB vorsieht (Art. 97 StGB). Nicht das konkrete Urteil ist massgebend, sondern die abstrakt angedrohte Höchststrafe. Je schwerer die angedrohte Strafe, desto länger die Verjährungsfrist — bis hin zur Unverjährbarkeit bei schwersten Delikten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Die im Straftatbestand abstrakt angedrohte Höchststrafe bestimmt die Frist.' }, { feld: 'optionen', id: 'opt-1', text: 'Das Alter des Täters ist für das Jugendstrafrecht relevant — nicht für Verjährungsfristen allgemein.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht das konkrete Urteil — das wäre logisch problematisch (Strafe nach Verjährungsende).' }, { feld: 'optionen', id: 'opt-3', text: 'Opferwünsche haben keinen Einfluss auf Verjährung.' } ] },
  { id: '6891ff65-e638-430f-a6ea-3e6fb91e14fd', fachbereich: 'Recht', musterlosung: 'Das Kopftuchverbot ist verfassungskonform. Art. 36 BV-Prüfung: (1) gesetzliche Grundlage im Schulgesetz, (2) öffentliches Interesse (religiöse Neutralität der Schule), (3) Verhältnismässigkeit (gilt nur im Unterricht), (4) Kerngehalt gewahrt (Rosalie kann privat Glauben ausüben). Der EGMR hat dies im Fall Dahlab gegen die Schweiz (2001) bestätigt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die gesetzliche Grundlage besteht im Schulgesetz — religiöse Neutralität ist normiert.' }, { feld: 'optionen', id: 'opt-1', text: 'Der Kerngehalt bleibt gewahrt — Glaubensausübung ausserhalb der Schule frei.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Alle fünf Kriterien von Art. 36 BV erfüllt — verfassungskonform.' }, { feld: 'optionen', id: 'opt-3', text: 'Religiöse Neutralität der Schule ist anerkanntes öffentliches Interesse.' } ] },
]

// duplizierten Eintrag filtern (nur einmal pro id)
const seen = new Set()
const filtered = updates.filter((u) => {
  if (seen.has(u.id)) return false
  seen.add(u.id)
  return true
})

const lines = filtered.map((u) => JSON.stringify(u)).join('\n') + '\n'
await fs.appendFile(OUT, lines)

const state = JSON.parse(await fs.readFile(STATE, 'utf8'))
state.letzteSession = new Date().toISOString()
state.verarbeitet = (state.verarbeitet || 0) + filtered.length
state.fragen = state.fragen || {}
for (const u of filtered) {
  state.fragen[u.id] = { status: 'done', zeitpunkt: state.letzteSession, teile: u.teilerklaerungen.length }
}
await fs.writeFile(STATE, JSON.stringify(state, null, 2))
console.log(`[s4] ${filtered.length} Updates | total ${state.verarbeitet}/${state.totalFragen}`)
